  8→int test(char* fname_src1,
  9→        char* fname_src2,
 10→        char* fname_scale1,
 11→        char* fname_scale2,
 12→        char* fname_golden,
 13→        uint16_t size,
 14→        uint16_t pre_rshift,
 15→        uint16_t out_scale,
 16→        uint16_t post_rshift)
 17→{
 18→    {
 19→        dump_param("size=%"PRIu16";pre_rshift=%"PRIu16";out_scale=%#"PRIx16
 20→            ";post_rshift=%"PRIu16, size, pre_rshift, out_scale, post_rshift);
 21→    }
 22→
 23→    FILE *fptr_in1, *fptr_in2, *fptr_scale1, *fptr_scale2, *fptr_golden;
 24→    //backup originally malloced starting address for later memory releasing
 25→    void *src1_ori, *src2_ori, *scale1_ori, *scale2_ori, *out_ori, *golden_ori;
 26→
 27→    q7_t *src1 = (q7_t*)test_malloc(sizeof(q7_t) * size, "src1", &src1_ori);
 28→    q7_t *src2 = (q7_t*)test_malloc(sizeof(q7_t) * size, "src2", &src2_ori);
 29→    q15_t *scale1 = (q15_t*)test_malloc(sizeof(q15_t) * size, "scale1", &scale1_ori);
 30→    q15_t *scale2 = (q15_t*)test_malloc(sizeof(q15_t) * size, "scale2", &scale2_ori);
 31→    q7_t *out = (q7_t*)test_malloc(sizeof(q7_t) * size, "out", &out_ori);
 32→    q7_t *golden = (q7_t*)test_malloc(sizeof(q7_t) * size, "golden", &golden_ori);
 33→
 34→    test_Fopen(fname_src1, "rb", &fptr_in1);
 35→    test_Fopen(fname_src2, "rb", &fptr_in2);
 36→    test_Fopen(fname_scale1, "rb", &fptr_scale1);
 37→    test_Fopen(fname_scale2, "rb", &fptr_scale2);
 38→    test_Fread(src1, sizeof(*src1), size, fptr_in1, "src1");
 39→    test_Fread(src2, sizeof(*src2), size, fptr_in2, "src2");
 40→    test_Fread(scale1, sizeof(*scale1), size, fptr_scale1, "scale1");
 41→    test_Fread(scale2, sizeof(*scale1), size, fptr_scale2, "scale2");
 42→    process_after_reading_input_data();
 43→
 44→#ifdef ENA_RUN_TWICE
 45→    riscv_nn_add_s8_sym(src1, src2, scale1, scale2, size, pre_rshift, out_scale, post_rshift, out);
 46→#endif
 47→
 48→    process_before_perf_measuring();
 49→#ifdef PF_COUNTER
 50→    startPFM;
 51→#endif
 52→    riscv_nn_add_s8_sym(src1, src2, scale1, scale2, size, pre_rshift, out_scale, post_rshift, out);
 53→#ifdef PF_COUNTER
 54→    stopPFM;
 55→    readResult();
 56→#endif
 57→
 58→#if ENA_DUMP_GOLDEN
 59→    test_Fopen(fname_golden, "wb+", &fptr_golden);
 60→    fwrite(out, sizeof(*golden), size, fptr_golden);
 61→    uint32_t retStatus = NDS_SUCCESS;
 62→#else
 63→    test_Fopen(fname_golden, "rb", &fptr_golden);
 64→    test_Fread(golden, sizeof(*golden), size, fptr_golden, "golden");
 65→    uint32_t retStatus = verify_buffer(out, golden, size, sizeof(*out), 0);
 66→#endif
 67→
 68→    test_free(&src1_ori);
 69→    test_free(&src2_ori);
 70→    test_free(&scale1_ori);
 71→    test_free(&scale2_ori);
 72→    test_free(&out_ori);
 73→    test_free(&golden_ori);
 74→    fclose(fptr_in1);
 75→    fclose(fptr_in2);
 76→    fclose(fptr_scale1);
 77→    fclose(fptr_scale2);
 78→    fclose(fptr_golden);
 79→
 80→    return retStatus;
 81→}
 82→
 83→int main (void)
 84→{
 85→    enable_fs_and_vs();
 86→    uint16_t size, pre_rshift, out_scale, post_rshift;
 87→    uint32_t retStatus=NDS_SUCCESS;
 88→
 89→#if !ENA_MEASURE_PERF
 90→    //test-1: column length less than VLEN
 91→    size = 3;
 92→    pre_rshift = 8;
 93→    out_scale = 3;
 94→    post_rshift = 11;
 95→    retStatus |= test("8b_in1.bin", "8b_in2.bin", "16b_in1.bin", "16b_in2.bin", "add_q7_2sft_golden.bin", size, pre_rshift, out_scale, post_rshift);
 96→
 97→    //test-2: column length more than VLEN
 98→    size = 71;
 99→    pre_rshift = 8;
100→    out_scale = 3;
101→    post_rshift = 11;
102→    retStatus |= test("8b_in1.bin", "8b_in2.bin", "16b_in1.bin", "16b_in2.bin", "add_q7_2sft_golden2.bin", size, pre_rshift, out_scale, post_rshift);
103→#endif
104→
105→    //test-3: max column length
106→    size = 60000;
107→    pre_rshift = 8;
108→    out_scale = 3;
109→    post_rshift = 10;
110→    retStatus |= test("8b_in1.bin", "8b_in2.bin", "16b_in1.bin", "16b_in2.bin", "add_q7_2sft_golden3.bin", size, pre_rshift, out_scale, post_rshift);
111→
112→    return retStatus;
113→}
